addpath('5g');addpath('5g/5g');addpath('5g/netmod');addpath('wirelessnetwork/wirelessnetwork');
try
  gnb = nrGNB(NumTransmitAntennas=128, NumResourceBlocks=51, SubcarrierSpacing=30e3, ChannelBandwidth=20e6, Position=[0 0 0]);
