%% NR Cell Performance — 128T128R Downlink MU-MIMO (Rel-19 eTypeII)
% Evaluates DL MU-MIMO system performance using abstract PHY (L2SM),
% 128-antenna gNB with eTypeII-r19 codebook (TS 38.214 §5.2.2.2.5a).
%
% Author: ThangTQ23 — VSI, 2026-04

%% 1. Simulation Setup

wirelessnetworkSupportPackageCheck

rng("default")
numFrameSimulation = 5;
networkSimulator   = wirelessNetworkSimulator.init;

%% 2. gNB Configuration
% 128T128R massive MIMO, TDD, 3.5 GHz n78, 20 MHz / 30 kHz SCS

% Quick simulation: use 10 MHz here (for speed). In reality you would use 100 MHz.
carrierFreq = 4.9e9;          % gNB carrier frequency = 4.9 GHz
channelBW    = 10e6;          % Channel bandwidth = 10 MHz (use 100e6 in real tests)
scs          = 30e3;          % Subcarrier spacing = 30 kHz (choose 15, 30, 60, ... per numerology)

% Compute NumResourceBlocks consistent with bandwidth:
% One RB occupies 12 subcarriers, each of width scs, so RB_bandwidth = 12 * scs.
numRB = floor(channelBW / (12 * scs));  % integer number of RBs that fit in channelBW

% Create gNB with matching parameters
gnb = nrGNB( ...
    CarrierFrequency = carrierFreq, ...
    ChannelBandwidth  = channelBW, ...
    SubcarrierSpacing = scs, ...
    NumResourceBlocks  = numRB);

% Display configured RBs
disp("Configured NumResourceBlocks = " + numRB);

%% 3. Scheduler Configuration
% CSI measurement source: "SRS" (TDD reciprocity) or "CSI-RS"

csiMeasurementSignalDLType = "CSI-RS";
allocationType             = 0;   % RAT-0 (RBG-based)


% MU-MIMO configuration defined using name = value pairs for easy editing
muMIMOConfiguration = struct( ...
    MaxNumUsersPaired = 2, ...   % maximum users paired in MU-MIMO
    MaxNumLayers      = 8, ...   % maximum spatial layers
    MinNumRBs         = 2, ...   % minimum RBs per user
    MinSINR           = 10 ...   % minimum SINR (dB) required for pairing;
);

% Configure scheduler on gNB using name = value pairs
configureScheduler(gNB, ...
    ResourceAllocationType = allocationType, ...
    MaxNumUsersPerTTI      = 10, ...
    MUMIMOConfigDL         = muMIMOConfiguration, ...
    CSIMeasurementSignalDL = csiMeasurementSignalDL);

%% 4. UE Deployment
% 10 UEs uniformly distributed at 500 m, azimuth ±60°

numUEs        = 10;               % number of UEs
meanDistance  = 500;              % mean radial distance from gNB (m)
distJitter    = 120;              % ± jitter in lateral direction (m)
elevationDeg  = 0;                % fixed elevation angle (deg)
azimuthRange  = [-60, 60];        % azimuth range (deg) around gNB
rng(1);                           % reproducible random positions

% UE radio/antenna settings (edit as needed)
ueRxGain                = 0;      % UE receive gain (dBi)
ueNumTxAntennas         = 1;      % UE transmit antennas
ueNumRxAntennas         = 4;      % UE receive antennas

% gNB position (example)
gNBPosition = [0 0 25];           % [x y z] of gNB (m)

% Generate UE relative spherical coordinates: [radius, azimuthDeg, elevationDeg]
radii   = ones(numUEs,1)*meanDistance;
azDeg   = azimuthRange(1) + (azimuthRange(2)-azimuthRange(1)).*rand(numUEs,1);
elDeg   = ones(numUEs,1)*elevationDeg;
ueRelPosition = [radii, azDeg, elDeg];

% Convert spherical (azimuth, elevation, radius) to Cartesian (x,y,z)
% sph2cart inputs: azimuth (rad), elevation (rad), radius
[xPos, yPos, zPos] = sph2cart(deg2rad(ueRelPosition(:,2)), ...
                              deg2rad(ueRelPosition(:,3)), ...
                              ueRelPosition(:,1));

% Absolute positions and names
uePositions = [xPos, yPos, zPos] + gNBPosition;
ueNames     = "UE-" + (1:numUEs);

% Create UE objects (use name = value syntax supported in recent releases)
UEs = nrUE( ...
    Name                 = ueNames, ...
    Position             = uePositions, ...
    ReceiveGain          = ueRxGain, ...
    NumTransmitAntennas  = ueNumTxAntennas, ...
    NumReceiveAntennas   = ueNumRxAntennas ...
);

% Connect UEs to gNB with simple DL full-buffer traffic and periodic CSI reports
connectUE(gNB, UEs, FullBufferTraffic = "DL", CSIReportPeriodicity = 10);

%% 5. Network Simulator — Add Nodes

addNodes(networkSimulator, gNB);
addNodes(networkSimulator, UEs);

%% 6. CDL Channel Model
% CDL-B, 100 ns delay spread, 5 Hz Doppler (frequency-selective, rank-friendly)

delayProfile         = "CDL-B";   % e.g., "CDL-A", "CDL-B", "CDL-C", ...
delaySpread          = 100e-9;    % delay spread (s) — adjust to match scenario
maximumDopplerShift  = 5;         % Doppler shift (Hz)
sampleRate           = [];        % sample rate (Hz) — set [] to use default from gNB/UE objects
applySeed            = 1;         % random seed for reproducibility (set [] for random)

% Build config as a struct (modern name = value syntax)
channelConfig = struct( ...
    DelayProfile = delayProfile, ...
    DelaySpread = delaySpread, ...
    MaximumDopplerShift = maximumDopplerShift, ...
    SampleRate = sampleRate, ...
    Seed = applySeed ...
);

% Create CDL channels from gNB and UE objects
channels = hNRCreateCDLChannels(channelConfig, gNB, UEs);

% Wrap into a custom channel model object and add to simulator
customChannelModel = hNRCustomChannelModel(channels);
addChannelModel(networkSimulator, @customChannelModel.applyChannelModel);

% Optional: display summary for verification
disp("Created " + numel(channels) + " CDL channel(s) with profile " + delayProfile);

%% 7. Logging and Visualization

enableTraces = true;

if enableTraces
    simSchedulingLogger = helperNRSchedulingLogger(numFrameSimulation, gNB, UEs);
    simPhyLogger        = helperNRPhyLogger(numFrameSimulation, gNB, UEs);
end

numMetricPlotUpdates = 200;
metricsVisualizer = helperNRMetricsVisualizer(gNB, UEs, ...
    RefreshRate=numMetricPlotUpdates, PlotSchedulerMetrics=true, ...
    PlotPhyMetrics=false, PlotCDFMetrics=true, LinkDirection=0);

simulationLogFile = "simulationLogs";

%% 8. Run Simulation

simulationTime = numFrameSimulation * 1e-2;   % seconds
run(networkSimulator, simulationTime);

%% 9. Results — KPI Summary
% Display cell throughput, spectral efficiency, and BLER ECDF.

displayPerformanceIndicators(metricsVisualizer);

%% 10. Save Traces

if enableTraces
    simulationLogs = cell(1,1);
    if gNB.DuplexMode == "FDD"
        logInfo = struct(DLTimeStepLogs=[], ULTimeStepLogs=[], ...
                         SchedulingAssignmentLogs=[], PhyReceptionLogs=[]);
        [logInfo.DLTimeStepLogs, logInfo.ULTimeStepLogs] = ...
            getSchedulingLogs(simSchedulingLogger);
    else  % TDD
        logInfo = struct(TimeStepLogs=[], SchedulingAssignmentLogs=[], ...
                         PhyReceptionLogs=[]);
        logInfo.TimeStepLogs = getSchedulingLogs(simSchedulingLogger);
    end
    logInfo.SchedulingAssignmentLogs = getGrantLogs(simSchedulingLogger);
    logInfo.PhyReceptionLogs         = getReceptionLogs(simPhyLogger);
    simulationLogs{1} = logInfo;
    save(simulationLogFile, "simulationLogs");
end

%% 11. MU-MIMO Pairing Analysis — UEs per RB Distribution
% Histogram shows how often multiple UEs share the same RB in DL slots,
% which is a direct indicator of MU-MIMO pairing effectiveness.

if enableTraces
    avgNumUEsPerRB = calculateAvgUEsPerRBDL(logInfo, gNB.NumResourceBlocks, ...
                                             allocationType, duplexType);
